// Get all items and filter out duplicates using workflow static data
const items = $input.all();

if (items.length === 0) {
  return [];
}

// Get published posts from workflow static data (persistent storage)
const staticData = $getWorkflowStaticData('global');
if (!staticData.publishedPosts) {
  staticData.publishedPosts = [];
}

const publishedUrls = new Set(staticData.publishedPosts.map(p => p.url));

// Filter out already published items
const newItems = items.filter(item => {
  const url = item.json.link || item.json.url || '';
  return url && !publishedUrls.has(url);
});

if (newItems.length === 0) {
  // All items already published
  return [];
}

// Pick random item from first 10 NEW items
const randomIndex = Math.floor(Math.random() * Math.min(newItems.length, 10));
const item = newItems[randomIndex].json;

const normalized = {
  title: (item.title || '').slice(0, 300),
  description: (item.contentSnippet || item.description || '').replace(/<[^>]*>/g, '').slice(0, 500),
  url: item.link || item.url || '',
  source: item.creator || item.author || 'Unknown'
};

if (!normalized.title || !normalized.url) {
  return [];
}

return [{ json: normalized }];

// Parse score and extract all data
const response = $input.first().json;
const originalItem = $('Pick One Random Item').item.json;

let score = 0;
let angle = '';
let hook = '';
let imagePrompt = 'futuristic AI technology concept, professional, minimalist, blue and purple tones, abstract digital art';

try {
  let content = response.message?.content || response.text || '';
  content = content.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(content);
  score = parseInt(parsed.score) || 0;
  angle = parsed.angle || '';
  hook = parsed.hook || '';
  imagePrompt = parsed.imagePrompt || imagePrompt;
} catch (e) {
  score = 6;
}

// Only continue if score >= 6
if (score >= 6) {
  return [{ json: { ...originalItem, score, angle, hook, imagePrompt } }];
} else {
  return [];
}

// FIXED: Correct extraction for Reve AI response format
// Reve AI returns: { data: [{ url: '...', b64_json: null }], meta: { usage: { tokens_used: X } } }

const items = $input.all();
const postData = items[0]?.json || {};
const imageResponse = items[1]?.json || {};

// Get post text
const postText = postData.message?.content || postData.text || '';

// DEBUG: Log the full Reve AI response to see what we're getting
console.log('=== REVE AI FULL RESPONSE ===');
console.log(JSON.stringify(imageResponse, null, 2));

let imageUrl = '';

// Check for errors first
if (imageResponse.error) {
  console.log('Reve AI Error:', imageResponse.error);
} else {
  // CORRECT Reve AI format: data[0].url
  if (imageResponse.data && Array.isArray(imageResponse.data) && imageResponse.data[0]) {
    imageUrl = imageResponse.data[0].url || '';
    console.log('Found URL in data[0].url:', imageUrl);
  }

  // Fallback checks for other possible formats
  if (!imageUrl) {
    imageUrl = 
      imageResponse.url ||
      imageResponse.image_url ||
      imageResponse.imageUrl ||
      imageResponse.output?.url ||
      imageResponse.result?.url ||
      (imageResponse.images && imageResponse.images[0]) ||
      '';
    if (imageUrl) console.log('Found URL in fallback:', imageUrl);
  }
}

// Validate URL format
if (imageUrl && typeof imageUrl === 'string') {
  imageUrl = imageUrl.trim();
  if (!imageUrl.startsWith('http://') && !imageUrl.startsWith('https://')) {
    console.log('Invalid URL format (not http/https):', imageUrl);
    imageUrl = '';
  }
} else {
  imageUrl = '';
}

const hasValidImage = !!(imageUrl && imageUrl.length > 10);
console.log('=== FINAL RESULT ===');
console.log('hasValidImage:', hasValidImage);
console.log('imageUrl:', imageUrl || 'NONE');
console.log('postText length:', postText.length);

return [{
  json: {
    postText: postText,
    imageUrl: imageUrl,
    hasValidImage: hasValidImage
  }
}];

// Combine post text with downloaded image binary
const downloadedImage = $input.first();
const preparedPost = $('Prepare LinkedIn Post').item.json;

console.log('=== DOWNLOAD IMAGE RESULT ===');
console.log('Has binary:', !!(downloadedImage.binary && Object.keys(downloadedImage.binary).length > 0));
if (downloadedImage.binary) {
  console.log('Binary keys:', Object.keys(downloadedImage.binary));
}

// Check if download was successful
if (downloadedImage.binary && Object.keys(downloadedImage.binary).length > 0) {
  return [{
    json: {
      postText: preparedPost.postText
    },
    binary: downloadedImage.binary
  }];
} else {
  // Download failed, post without image
  console.log('Download failed, posting without image');
  return [{
    json: {
      postText: preparedPost.postText
    }
  }];
}

// Save published post to workflow static data (prevents duplicates)
const staticData = $getWorkflowStaticData('global');

if (!staticData.publishedPosts) {
  staticData.publishedPosts = [];
}

// Get the original item data
const originalItem = $('Check Score >= 6').item.json;

// Add to published list
staticData.publishedPosts.push({
  url: originalItem.url,
  title: originalItem.title,
  publishedAt: new Date().toISOString()
});

// Keep only last 500 posts to prevent memory issues
if (staticData.publishedPosts.length > 500) {
  staticData.publishedPosts = staticData.publishedPosts.slice(-500);
}

return $input.all();

